"use strict";(self.webpackChunksysanalyst_kb=self.webpackChunksysanalyst_kb||[]).push([["6366"],{44503(i){i.exports=JSON.parse('{"tag":{"label":"tracking","permalink":"/sysanalyst-kb.github.io/docs/tags/tracking","allTagsPath":"/sysanalyst-kb.github.io/docs/tags","count":3,"items":[{"id":"specialization/gamedev-sdk","title":"SDK-\u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u0438 \u0432 \u0438\u0433\u0440\u0430\u0445 \u2014 Firebase, GameAnalytics, Push","description":"\u041C\u043E\u0431\u0438\u043B\u044C\u043D\u0430\u044F \u0438\u0433\u0440\u0430 \u2014 \u043D\u0435 \u0438\u0437\u043E\u043B\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u043E\u0435 \u043F\u0440\u0438\u043B\u043E\u0436\u0435\u043D\u0438\u0435. \u041E\u043D\u0430 \u0438\u043D\u0442\u0435\u0433\u0440\u0438\u0440\u0443\u0435\u0442 5\u201310+ SDK (Analytics, Push, Crash, Monetization, Attribution). \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u0443\u0435\u0442, \u043A\u0430\u043A\u0438\u0435 SDK \u043D\u0443\u0436\u043D\u044B, \u043A\u0430\u043A\u0438\u0435 \u0441\u043E\u0431\u044B\u0442\u0438\u044F \u043E\u043D\u0438 \u0448\u043B\u044E\u0442, \u043A\u0430\u043A \u0434\u0430\u043D\u043D\u044B\u0435 \u0442\u0435\u043A\u0443\u0442 \u043E\u0442 \u043A\u043B\u0438\u0435\u043D\u0442\u0430 \u0432 DWH \u0438 \u043A\u0430\u043A\u0438\u0435 \u0440\u0438\u0441\u043A\u0438 \u0443 \u043A\u0430\u0436\u0434\u043E\u0439 \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u0438. \u0413\u043B\u0430\u0432\u043D\u043E\u0435: SDK \u2014 \u044D\u0442\u043E \u043A\u043E\u0434 \u0432 \u043A\u043B\u0438\u0435\u043D\u0442\u0435, \u0435\u0433\u043E \u043D\u0430\u0434\u043E \u0442\u0435\u0441\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C, \u043E\u0431\u043D\u043E\u0432\u043B\u044F\u0442\u044C \u0438 \u043C\u043E\u043D\u0438\u0442\u043E\u0440\u0438\u0442\u044C. \u041E\u0448\u0438\u0431\u043A\u0430 \u0432 SDK \u043C\u043E\u0436\u0435\u0442 \u0441\u0442\u043E\u0438\u0442\u044C revenue (\u043F\u043E\u0442\u0435\u0440\u044F\u043D\u043D\u044B\u0435 \u0441\u043E\u0431\u044B\u0442\u0438\u044F) \u0438\u043B\u0438 \u0440\u0435\u0439\u0442\u0438\u043D\u0433\u0430 (\u043A\u0440\u0430\u0448).","permalink":"/sysanalyst-kb.github.io/docs/specialization/gamedev-sdk"},{"id":"specialization/logistics-last-mile","title":"\u0414\u043E\u0441\u0442\u0430\u0432\u043A\u0430 \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0435\u0439 \u043C\u0438\u043B\u0438 \u0438 \u0442\u0440\u0435\u043A\u0438\u043D\u0433","description":"\u041F\u043E\u0441\u043B\u0435\u0434\u043D\u044F\u044F \u043C\u0438\u043B\u044F \u2014 \u0444\u0438\u043D\u0430\u043B\u044C\u043D\u044B\u0439 \u044D\u0442\u0430\u043F \u0434\u043E\u0441\u0442\u0430\u0432\u043A\u0438 \u043E\u0442 \u0441\u043A\u043B\u0430\u0434\u0430/\u0445\u0430\u0431\u0430/\u041F\u0412\u0417 \u0434\u043E \u043A\u043B\u0438\u0435\u043D\u0442\u0430. \u0421\u0430\u043C\u044B\u0439 \u0434\u043E\u0440\u043E\u0433\u043E\u0439 (40-60% \u0441\u0442\u043E\u0438\u043C\u043E\u0441\u0442\u0438 \u043B\u043E\u0433\u0438\u0441\u0442\u0438\u043A\u0438) \u0438 \u043A\u043B\u0438\u0435\u043D\u0442\u043E\u043E\u0440\u0438\u0435\u043D\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u044B\u0439 \u044D\u0442\u0430\u043F. \u041A\u043B\u044E\u0447\u0435\u0432\u044B\u0435 \u0430\u0441\u043F\u0435\u043A\u0442\u044B \u042F\u043D\u0434\u0435\u043A\u0441.\u0414\u043E\u0441\u0442\u0430\u0432\u043A\u0430 (100K+ \u0437\u0430\u043A\u0430\u0437\u043E\u0432/\u0434\u0435\u043D\u044C), \u0421\u0414\u042D\u041A, Boxberry, 5Post.","permalink":"/sysanalyst-kb.github.io/docs/specialization/logistics-last-mile"},{"id":"requirements/traceability","title":"\u0422\u0440\u0430\u0441\u0441\u0438\u0440\u043E\u0432\u043A\u0430 \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u0439","description":"\u0422\u0440\u0430\u0441\u0441\u0438\u0440\u043E\u0432\u043A\u0430 (traceability) \u2014 \u044D\u0442\u043E \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u043E\u0441\u0442\u044C \u043F\u0440\u043E\u0441\u043B\u0435\u0434\u0438\u0442\u044C \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u0435 \u043E\u0442 \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u0430 (\u0438\u043D\u0442\u0435\u0440\u0432\u044C\u044E, \u0437\u0430\u043A\u043E\u043D) \u0434\u043E \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438 (\u043A\u043E\u0434, \u0442\u0435\u0441\u0442) \u0438 \u043E\u0431\u0440\u0430\u0442\u043D\u043E.","permalink":"/sysanalyst-kb.github.io/docs/requirements/traceability"}],"unlisted":false}}')}}]);